// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC /* Special License Rights * The Government's rights to use, display, or disclose this software are restricted. * Any reproduction of computer software, computer software documentation, * or portions thereof marked with this legend must also reproduce the markings. */ // Script Continued Below //------------------------------------------------------------------------------------------------------------------------ // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering // some special characters in "instruction" or "Signature Instructions" field // Instructions and Signature Instructions need HTML converted to string before // the call to substring with field.maxChars; // Update .href to use dot notation for state and order // Combined Template Widget Data into here; // 2.7.0 | 2021-11-16 | raj | STRY0113839 - Technical Story: Pages/Portal/Page should be picked up from the "Form preferences" // NOTE: href was no longer used. So, removed completely to avoid future confusion //------------------------------------------------------------------------------------------------------------------------
var TaskWidgetData = Class.create(); TaskWidgetData.prototype = { initialize: function() {}, // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode // Use this Server side function to convert HTML to a simple string convertHtmlToSimpleString: function(someHtmlText) { someHtmlText = someHtmlText + '';
return someHtmlText.replace(/<\/?[^>]+(>|$)/g, ''); },
// STRY0116812 loadOfficeTreeFieldsAndFieldLabels: function(gr) { // load all of the field names used in the template tree nodes return { 'active': { fieldName: 'active', fieldLabel: gr.active.getLabel(), type: 'boolean', hasValue: true, keyUsesDisplayOnly: true, hasDiplayValue: true, maxChars: 0 }, 'office_abbreviation': { fieldName: 'office_abbreviation', fieldLabel: gr.office_abbreviation.getLabel(), type: 'string', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'office_level': { fieldName: 'office_level', fieldLabel: gr.office_level.getLabel(), type: 'number', hasValue: true, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'office_name': { fieldName: 'office_name', fieldLabel: gr.office_name.getLabel(), type: 'string', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'u_outstanding_request_count': { fieldName: 'u_outstanding_request_count', fieldLabel: gr.u_outstanding_request_count.getLabel(), type: 'number', hasValue: true, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'parent': { fieldName: 'parent', fieldLabel: gr.parent.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: false, maxChars: 0 }, 'tasking_authorities': { fieldName: 'tasking_authorities', fieldLabel: gr.tasking_authorities.getLabel(), type: 'list', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'u_ou_hierarchy_administrators': { fieldName: 'u_ou_hierarchy_administrators', fieldLabel: gr.u_ou_hierarchy_administrators.getLabel(), type: 'list', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'u_ou_is_permissive': { fieldName: 'u_ou_is_permissive', fieldLabel: gr.u_ou_is_permissive.getLabel(), type: 'boolean', hasValue: true, keyUsesDisplayOnly: true, hasDiplayValue: true, maxChars: 0 }, 'u_ou_primary_contact': { fieldName: 'u_ou_primary_contact', fieldLabel: gr.u_ou_primary_contact.getLabel(), // STRY0114453 type: 'profile', hasValue: true, keyUsesDisplayOnly: true, hasDiplayValue: true, maxChars: 0 } }; },
// 2.6 STRY0091307 loadTaskListTreeFieldsInModelAndFieldLabels: function(gr) { // load all of the field names used in the task tree nodes return { 'assigned_to': { fieldName: 'assigned_to', fieldLabel: gr.assigned_to.getLabel(), type: 'reference', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'primary_assignee': { fieldName: 'primary_assignee', fieldLabel: gr.primary_assignee.getLabel(), type: 'reference', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'task_name': { fieldName: 'task_name', fieldLabel: gr.task_name.getLabel(), type: 'string', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'state': { fieldName: 'state', fieldLabel: gr.state.getLabel(), type: 'string', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'parent': { fieldName: 'parent', fieldLabel: gr.parent.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: false, maxChars: 0 }, 'calchaschildren': { fieldName: 'calchaschildren', fieldLabel: gr.calchaschildren.getLabel(), type: 'number', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: false, maxChars: 0 }, 'order': { fieldName: 'order', fieldLabel: gr.order.getLabel(), type: 'string', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 } }; },
// 2.6 STRY0091307 loadTaskTreeFieldsInModelAndFieldLabels: function(gr) { // load all of the field names used in the task tree nodes return { 'assigned_to': { fieldName: 'assigned_to', fieldLabel: gr.assigned_to.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, // DFCT0010684 'u_task_requester': { fieldName: 'u_task_requester', fieldLabel: gr.u_task_requester.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'calchaschildren': { fieldName: 'calchaschildren', fieldLabel: gr.calchaschildren.getLabel(), type: 'number', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: false, maxChars: 0 }, 'classification': { fieldName: 'classification', fieldLabel: gr.classification.getLabel(), type: 'choice', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'decision': { fieldName: 'decision', fieldLabel: gr.decision.getLabel(), type: 'string', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'order': { fieldName: 'order', fieldLabel: gr.order.getLabel(), type: 'string', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'instructions': { fieldName: 'instructions', fieldLabel: gr.instructions.getLabel(), type: 'string', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 300 }, 'parent': { fieldName: 'parent', fieldLabel: gr.parent.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: false, maxChars: 0 }, 'primary_assignee': { fieldName: 'primary_assignee', fieldLabel: gr.primary_assignee.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'primary_office': { fieldName: 'primary_office', fieldLabel: gr.primary_office.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'priority': { fieldName: 'priority', fieldLabel: gr.priority.getLabel(), type: 'choice', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'risk_flag': { fieldName: 'risk_flag', fieldLabel: gr.risk_flag.getLabel(), type: 'choice', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'state': { fieldName: 'state', fieldLabel: gr.state.getLabel(), type: 'choice', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'status': { fieldName: 'status', fieldLabel: gr.status.getLabel(), type: 'choice', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'status_reason': { fieldName: 'status', fieldLabel: gr.status.getLabel(), type: 'choice', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'suspense_date': { fieldName: 'suspense_date', fieldLabel: gr.suspense_date.getLabel(), type: 'date', hasValue: false, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'task_name': { fieldName: 'task_name', fieldLabel: gr.task_name.getLabel(), type: 'string', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'tasker_type': { fieldName: 'tasker_type', fieldLabel: gr.tasker_type.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'tasking_authority': { fieldName: 'tasking_authority', fieldLabel: gr.tasking_authority.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'u_active_subtasks': { fieldName: 'u_active_subtasks', fieldLabel: gr.u_active_subtasks.getLabel(), type: 'number', hasValue: true, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'u_external_due_date': { fieldName: 'u_external_due_date', fieldLabel: gr.u_external_due_date.getLabel(), type: 'date', hasValue: false, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'u_reviewer': { fieldName: 'u_reviewer', fieldLabel: gr.u_reviewer.getLabel(), type: 'reference', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'u_signature_instructions': { fieldName: 'u_signature_instructions', fieldLabel: gr.u_signature_instructions.getLabel(), type: 'string', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 300 }, 'u_wait_for_subtasks_to_finish': { fieldName: 'u_wait_for_subtasks_to_finish', fieldLabel: gr.u_wait_for_subtasks_to_finish.getLabel(), type: 'boolean', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: false, maxChars: 0 } }; },
// 2.6 STRY0091307 loadTemplateTreeFieldsInModelAndFieldLabels: function(gr) { // load all of the field names used in the template tree nodes return { 'active': { fieldName: 'active', fieldLabel: gr.active.getLabel(), type: 'boolean', hasValue: true, keyUsesDisplayOnly: true, hasDiplayValue: true, maxChars: 0 }, 'assigned_to_individual': { fieldName: 'assigned_to_individual', fieldLabel: gr.assigned_to_individual.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'calchaschildren': { fieldName: 'calchaschildren', fieldLabel: gr.calchaschildren.getLabel(), type: 'number', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: false, maxChars: 0 }, 'classification': { fieldName: 'classification', fieldLabel: gr.classification.getLabel(), type: 'choice', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'duration': { fieldName: 'duration', fieldLabel: gr.duration.getLabel(), type: 'date', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'u_duration_days': { fieldName: 'u_duration_days', fieldLabel: gr.u_duration_days.getLabel(), type: 'number', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'u_duration_time_due': { fieldName: 'u_duration_time_due', fieldLabel: gr.u_duration_time_due.getLabel(), type: 'time', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'warning_hours': { fieldName: 'warning_hours', fieldLabel: gr.warning_hours.getLabel(), type: 'number', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'instructions': { fieldName: 'instructions', fieldLabel: gr.instructions.getLabel(), type: 'string', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 300 }, 'number': { fieldName: 'number', fieldLabel: gr.number.getLabel(), type: 'number', hasValue: true, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'parent': { fieldName: 'parent', fieldLabel: gr.parent.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: false, maxChars: 0 }, 'primary_assignee': { fieldName: 'primary_assignee', fieldLabel: gr.primary_assignee.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'primary_office': { fieldName: 'primary_office', fieldLabel: gr.primary_office.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'route_order': { fieldName: 'route_order', fieldLabel: gr.route_order.getLabel(), type: 'string', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'short_description': { fieldName: 'short_description', fieldLabel: gr.short_description.getLabel(), type: 'string', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'tasker_type': { fieldName: 'tasker_type', fieldLabel: gr.tasker_type.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'tasking_authority': { fieldName: 'tasking_authority', fieldLabel: gr.tasking_authority.getLabel(), type: 'reference', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'u_priority': { fieldName: 'u_priority', fieldLabel: gr.u_priority.getLabel(), type: 'choice', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'u_reviewer': { fieldName: 'u_reviewer', fieldLabel: gr.u_reviewer.getLabel(), type: 'reference', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 0 }, 'u_risk_flag': { fieldName: 'u_risk_flag', fieldLabel: gr.u_risk_flag.getLabel(), type: 'choice', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: true, maxChars: 0 }, 'u_signature_instructions': { fieldName: 'u_signature_instructions', fieldLabel: gr.u_signature_instructions.getLabel(), type: 'string', hasValue: false, keyUsesDisplayOnly: true, hasDiplayValue: false, maxChars: 300 }, 'u_wait_for_subtasks_to_finish': { fieldName: 'u_wait_for_subtasks_to_finish', fieldLabel: gr.u_wait_for_subtasks_to_finish.getLabel(), type: 'boolean', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: false, maxChars: 0 }, 'u_warning_projected_due_date_after_parent': { fieldName: 'u_warning_projected_due_date_after_parent', fieldLabel: gr.u_warning_projected_due_date_after_parent.getLabel(), type: 'boolean', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: false, maxChars: 0 }, 'u_warning_projected_due_date_before_child': { fieldName: 'u_warning_projected_due_date_before_child', fieldLabel: gr.u_warning_projected_due_date_before_child.getLabel(), type: 'boolean', hasValue: true, keyUsesDisplayOnly: false, hasDiplayValue: false, maxChars: 0 } }; },
// STRY0116812 buildOUMap: function(widgetId, map, grOU, fields) { var isGHA = new UserInfoScripts().UserHasRole('x_153465_discovert.tasker_organizational_admin'); var currentUser = gs.getUserID(); var ouO = this.getTaskListTreeLevelO(grOU, fields, grOU.office_level, widgetId); this.setAdminBooleans(grOU, ouO, isGHA, currentUser); // the top node of the tree cannot have a parent delete ouO.parent; map.push(ouO);
// technically level not used for Office as it is a field in the org this.getOUs(widgetId, fields, ouO.level, map, ouO, ouO.sys_id, isGHA, currentUser); },
// this is a recursive function used to load all tasks in the task tree into the Data for widgets getOUs: function(widgetId, fields, level, map, ouO, sys_id, isGHA, currentUser) { var grOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy'); grOU.addQuery('parent', sys_id); grOU.orderBy('level_order'); grOU.orderBy('office_name'); grOU.query(); while (grOU.next()) { var office_level = parseInt(grOU.office_level); var ouLevelO = this.getTaskListTreeLevelO(grOU, fields, office_level, widgetId); this.setAdminBooleans(grOU, ouLevelO, isGHA, currentUser); map.push(ouLevelO); this.getOUs(widgetId, fields, office_level, map, ouLevelO, grOU.getUniqueValue(), isGHA, currentUser); } },
setAdminBooleans: function(grOU, ouO, isGHA, currentUser){ var ouHAValue = grOU.getValue('u_ou_hierarchy_administrators'); ouO.isAdmin = (isGHA || (ouHAValue && ouHAValue.indexOf(currentUser)>=0)); },
// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode; combined Task and Template widget data code buildTaskMap: function(widgetId, map, gr, fields) { var taskO = this.getTaskListTreeLevelO(gr, fields, 1, widgetId);
// the top node of the tree cannot have a parent delete taskO.parent;
if (widgetId == 'discovertasker-processtemplatetreegraph') { // STRY0097904 taskO.process_level_map = gr.tasker_process_definition.process_level.getDisplayValue(); taskO.process_name_map = gr.number.toString() + ' - ' + gr.short_description.toString(); }
map.push(taskO);
if (widgetId == 'discovertasker-processtemplatetreegraph') { this.getTemplateTasks(widgetId, fields, map, taskO.level, taskO, taskO.sys_id); } else { this.getTasks(widgetId, fields, taskO.level, map, taskO, taskO.sys_id); } },
// this is a recursive function used to load all tasks in the task tree into the Data for widgets getTasks: function(widgetId, fields, level, map, taskO, sys_id) { var grTask = new GlideRecord('x_153465_discovert_route_task_instance'); grTask.addQuery('parent', sys_id); grTask.orderBy('order'); grTask.orderBy('number'); grTask.query(); var parentAfterAllChildren = true; while (grTask.next()) { if (!grTask.canRead()) { continue; } var taskLevelO = this.getTaskListTreeLevelO(grTask, fields, level, widgetId); map.push(taskLevelO); this.getTasks(widgetId, fields, level + 1, map, taskLevelO, grTask.getUniqueValue()); if (widgetId == 'discovertasker-recursivetasktreegraph') { if (taskLevelO.suspense_date > taskO.suspense_date) { parentAfterAllChildren = false; taskLevelO.warning.isSuspenseDateAfterParent = true; } } } if (widgetId == 'discovertasker-recursivetasktreegraph') { // STRY0095748 - no suspensedate warning taskO.warning.noSuspenseDate = (taskO.suspense_date == '' || taskO.suspense_date == null); taskO.warning.waitStatewithNoSubtasks = (taskO.u_wait_for_subtasks_to_finish && (taskO.calchaschildren == 0)); taskO.warning.isSuspenseDateAfterChildren = parentAfterAllChildren; taskO.warning.primaryAssigneeEmpty = (taskO.primary_assignee == '' || taskO.primary_assignee == null); taskO.warning.assignedMemberEmpty = (taskO.assigned_to == '' || taskO.assigned_to == null); } }, //Get Template Tasks Level 1++ getTemplateTasks: function(widgetId, fields, map, level, TemplateTaskO, sys_id) { var grTempTask = new GlideRecordSecure('x_153465_discovert_route_tasks'); grTempTask.addQuery('parent', sys_id); grTempTask.orderBy('route_order'); grTempTask.orderBy('number'); grTempTask.query();
while (grTempTask.next()) { var taskLevelO = this.getTaskListTreeLevelO(grTempTask, fields, level, widgetId); // STRY0117609 - if parent task is inactive, make task inactive if(!TemplateTaskO.active){ taskLevelO.inActiveDueToParent = taskLevelO.active && !TemplateTaskO.active; taskLevelO.active = TemplateTaskO.active; } map.push(taskLevelO); this.getTemplateTasks(widgetId, fields, map, level + 1, taskLevelO, grTempTask.getUniqueValue()); } if (widgetId == 'discovertasker-processtemplatetreegraph') { TemplateTaskO.warning.waitStatewithNoSubtasks = (TemplateTaskO.u_wait_for_subtasks_to_finish && (TemplateTaskO.calchaschildren == 0));
TemplateTaskO.warning.primaryAssigneeEmpty = (TemplateTaskO.primary_assignee == '' || TemplateTaskO.primary_assignee == null);
// STRY0095897 TemplateTaskO.warning.taskingAuthorityEmpty = (TemplateTaskO.tasking_authority == '' || TemplateTaskO.tasking_authority == null); TemplateTaskO.warning.primaryOfficeEmpty = (TemplateTaskO.primary_office == '' || TemplateTaskO.primary_office == null); } }, // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode; Task and Template widget data is same code getTaskListTreeLevelO: function(record, fields, level, widgetId) { var displayValue = ''; var newNodeData = {}; var sys_id = record.getUniqueValue(); newNodeData.key = sys_id; newNodeData.sys_id = sys_id; newNodeData.level = level; var current_user = gs.getUserID();
// STRY0109208, STRY0109209 - Add Create Icons var table = record.getRecordClassName(); if (table == 'x_153465_discovert_route_tasks'){ newNodeData.canCreate = new UserInfoScripts().userHasProcessRights(record); } else if(table == 'x_153465_discovert_route_task_instance'){ // NOTE: this should go into script include and be called from there newNodeData.canCreateSubTask = new uiConditionCheck().canCreateSubTask(record); } for (var key in fields) { var field = fields[key]; // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode // displayValue = record.getDisplayValue(key) + ''; if ((field.fieldName == 'u_signature_instructions') || (field.fieldName == 'instructions')) { displayValue = this.convertHtmlToSimpleString(record.getDisplayValue(key) + ''); } else { displayValue = record.getDisplayValue(key) + ''; }
if (field.maxChars > 0) { displayValue = displayValue.toString().length > field.maxChars ? displayValue.substring(0, field.maxChars - 1) : displayValue.toString(); }
if (field.keyUsesDisplayOnly) { newNodeData[key] = displayValue; } if (field.hasValue) { newNodeData[key] = record.getValue(key); } if (field.hasDiplayValue) { newNodeData[key + '_DisplayValue'] = displayValue; } // STRY0116812 switch (field.type){ case 'date': var date_number = record[key].dateNumericValue(); newNodeData[key] = date_number; break; case 'time': var time_number = 0; if(record.getValue(key) && record[key].dateNumericValue()>0){ var gdTime = new GlideDateTime(record.getValue(key)); var localTime = gdTime.getLocalTime(); time_number = (localTime.getHourOfDayLocalTime() * 60 + localTime.getMinutesLocalTime() * 60 + localTime.getSeconds()) * 1000; } newNodeData[key] = time_number; break; case 'boolean': var boolean_value = record[key] == 1 || record[key] == true; newNodeData[key] = boolean_value; break; case 'number': newNodeData[key] = record.getValue(key)==null?0:parseInt(record.getValue(key)); break; // STRY0114453 case 'profile': case 'photo': // load the photo name and the photo for both profile and photo newNodeData[key + '_photoName'] = displayValue; var profile = new GlideRecord("live_profile"); profile.addQuery("document", newNodeData[key]); profile.query(); while (profile.next()){ var photo = profile.getDisplayValue("photo"); if (photo.length > 0) { newNodeData[key + '_photo'] = photo + '?t=small'; } } // STRY0114453 if(field.type=='profile'){ var profileInfo = this.loadProfileInfo(newNodeData[key]); newNodeData[key + '_profile'] = profileInfo; }
break; case 'list': var list_value = record[key] == null || record[key] == undefined ? '': record[key]; newNodeData[key] = list_value;
// load the list into the Map newNodeData[key + '_list'] = []; var listArray = displayValue.split(','); for(var i=0; i<listArray.length; i++){ var arrayItem = {}; arrayItem.displayName = listArray[i]; if(arrayItem.displayName != null && arrayItem.displayName != undefined && arrayItem.displayName != ''){ newNodeData[key + '_list'].push(arrayItem); } } break; }
}
// These are the custom fields in this data set, compare with other data sets and determine best way to bring together. // STRY0113880 - DFCT0010761 - changed if to case switch(widgetId){ case 'discovertasker-recursivetasktreelist': // Load the text for the Task Tree List // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode // newNodeData.text = this.getTaskTreeListTitleNode(newNodeData, newNodeData.parent, newNodeData.task_name, newNodeData.primary_assignee, newNodeData.assigned_to, newNodeData.state, newNodeData.order); newNodeData.text = this.getTaskTreeListTitleNode(newNodeData);
// we will expand all on initial page load newNodeData.expanded = true; // NOTE you are here, there is an issue with leaf nodes having the down chevron when they should not // this should be removed // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering break; case 'discovertasker-recursivetasktreegraph': // Load the name value for the Task Tree Graph // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode; combined Task and Template widget data code newNodeData.name = this.getTaskTitleNode(record); newNodeData.warning = {}; newNodeData.isInboundExternalOU = !record.parent && record.tasking_authority && (record.tasking_authority.u_external_flag == true); newNodeData.warning.isTopSuspenseDateAfterExternalInboundDate = newNodeData.isInboundExternalOU && (record.suspense_date > record.u_external_due_date); newNodeData.isOutboundExternalOU = (record.outbound == true); newNodeData.warning.isTopSuspenseDateBeforeExternalOutboundDate = newNodeData.isOutboundExternalOU && (record.u_external_due_date > record.suspense_date); break; case 'discovertasker-processtemplatetreegraph': // Load the name value for the Template Task Tree Graph newNodeData.name = this.getTemplateTitleNode(record); newNodeData.warning = {}; // STRY0110317 calculate the due date to be set using days and Time newNodeData.actualTime = 0; if(newNodeData.u_duration_days >= 0){ newNodeData.actualTime = newNodeData.u_duration_days * 86400000; } if(newNodeData.u_duration_time_due >= 0){ newNodeData.actualTime+= newNodeData.u_duration_time_due; } break; case 'discovertasker-officehierarchy': // Load the name value for the Office Hierarchy // STRY0113880 - DFCT0010761 newNodeData.name = newNodeData.office_name + '\n (' + newNodeData.office_abbreviation + ')'; }
return newNodeData; },
// STRY0114453 loadProfileInfo: function(userGUID) { // MWMTest added photo var userProfile = { sys_id: userGUID, name: '', first_name: '', last_name: '', middle_name: '', email: '', phone: '', location: '', time_zone: '', photo: '' }; var grUser = new GlideRecord('sys_user'); if(grUser.get(userGUID)){ // MWMTest added getDisplayValue userProfile.name = grUser.getDisplayValue('name'); userProfile.first_name = grUser.getDisplayValue('first_name'); userProfile.last_name = grUser.getDisplayValue('last_name'); userProfile.middle_name = grUser.getDisplayValue('middle_name'); userProfile.email = grUser.getDisplayValue('email'); userProfile.phone = grUser.getDisplayValue('phone'); userProfile.location = grUser.getDisplayValue('location'); // if no user time zone, but location is loaded if(grUser.time_zone){ userProfile.time_zone = grUser.getDisplayValue('time_zone'); // + ''; } else if(grUser.location && grUser.location.time_zone){ userProfile.time_zone = gs.getMessage("Tasker - (location) - ") + userProfile.location.time_zone; } } return userProfile; },
// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode // re-write function to use local var's; remove badgeclass and taskText.state getTaskTreeListTitleNode: function(newNodeData) { var assignedTo = ''; var taskNameNumber = newNodeData.task_name; var taskText = {};
