ateTask.primary_assignee.getDisplayValue().toString() + ')'; if ((grTemplateTask.parent != '') && (parseInt(grTemplateTask.route_order.getDisplayValue().toString()) > 0)) { nodeTitle = grTemplateTask.route_order.getDisplayValue().toString() + ". " + nodeTitle; }
